import { Injectable, Logger } from "@nestjs/common";

import { DK_API_ENDPOINTS } from "./dk-api-endpoints";
import { DK_RESPONSE_CODES } from "./dk-response-codes";
import { DKClientService } from "./dk-client.service";
import type { PaymentStatusResponse } from "../../dtos/verify-payment-status-response.dto";

export interface DKPaymentStatusRequest extends Record<string, unknown> {
  request_id: string;
  transaction_id: string;
  bene_account_number: string;
}

@Injectable()
export class DKPaymentStatusService {
  private readonly logger = new Logger(DKPaymentStatusService.name);

  constructor(private readonly dkClient: DKClientService) {}

  async verifyStatus(
    request: DKPaymentStatusRequest,
  ): Promise<PaymentStatusResponse> {
    try {
      this.logger.log(
        `📤 [DK-PAYMENT-STATUS] Endpoint: ${DK_API_ENDPOINTS.TRANSACTION.STATUS}`,
      );
      this.logger.log(
        `📤 [DK-PAYMENT-STATUS] Request Body: ${JSON.stringify(request, null, 2)}`,
      );

      // Use the status endpoint (/v1/transaction/status) with the new 3-parameter format
      const response = await this.dkClient.post<PaymentStatusResponse>(
        DK_API_ENDPOINTS.TRANSACTION.STATUS,
        request,
      );

      this.logger.log(`📥 [DK-PAYMENT-STATUS] === RAW DK GATEWAY RESPONSE ===`);
      this.logger.log(
        `📥 [DK-PAYMENT-STATUS] Raw Response: ${JSON.stringify(response, null, 2)}`,
      );
      this.logger.log(`📥 [DK-PAYMENT-STATUS] === END RAW RESPONSE ===`);

      if (response.response_code === DK_RESPONSE_CODES.SUCCESS) {
        this.logger.log(
          `✅ [DK-PAYMENT-STATUS] Payment status verification successful for transaction: ${request.transaction_id}`,
        );
      } else {
        this.logger.warn(
          `⚠️ [DK-PAYMENT-STATUS] Payment status verification returned non-success code: ${response.response_code} - ${response.response_description}`,
        );
      }

      return response;
    } catch (error) {
      this.logger.error(
        `❌ [DK-PAYMENT-STATUS] Failed to verify payment status for transaction: ${request.transaction_id}`,
        error,
      );

      // Return a generic error response in case of exceptions
      return {
        response_code: "5001",
        response_status: "Exception",
        response_description:
          "Exception occurred while checking payment status",
        meta_info: null,
        status: null,
        response_data: null,
      };
    }
  }
}
